mapper.select:
SELECT 
FROM monthly_report
WHERE user_id = #{userId}
  AND report_year = #{year}
  AND report_month = #{month}

SELECT 
FROM monthly_report
WHERE user_id = #{userId}
  AND (report_year < #{year}
       OR (report_year = #{year} AND report_month < #{month}))
ORDER BY report_year DESC, report_month DESC
LIMIT #{limit}

mapper.update:
UPDATE monthly_report
SET user_message = #{userMessage},
    gulbi_reply  = #{gulbiReply},
    replied_at   = #{repliedAt}
WHERE id = #{id}
